            [178061L] = new()
            {
                Id = 178061L,
                Name = "BS Zelda no Densetsu: Inishie no Sekiban - Dai-1-wa",
                Slug = "bs-zelda-no-densetsu-inishie-no-sekiban-dai-1-wa",
                Summary = "The first part (week) of BS Zelda no Densetsu: Inishie no Sekiban.",
                Storyline =
                    "The Hero of Light - Week 1\nThe events of Ancient Stone Tablets occur a mere six years after the destruction of Ganon by the hero, Link in A Link to the Past. Hyrule is enjoying a time of peace and tranquility, but Princess Zelda suffers from a dark, recurring dream showing a shadow over a temple; a premonition of evil to come. One day, she witnesses a mysterious and brilliant light in the sky to the east. Aginah, the younger brother of the wise man Sahasrahla and now living in his old hideout near the Eastern Palace also witnesses such a light, and travels to investigate. There he finds a strange youth lying on the ground. Zelda, also following the light, meets up with Aginah, and they both carry the child to rest in Sahasrahla\u0027s hideout. Confused by the youth\u0027s unusual clothes, they believe the child not to hail from Kakariko Village. Speaking to Aginah while the youngster sleeps, Zelda learns that his brother Sahasrahla had also sensed danger surrounding Hyrule and had left the land to find the hero, Link. While Link has not yet returned, Zelda senses that if this new youth was endowed with courage, he or she may be the Hero of Light.",
                FirstReleaseDate = new DateTime(629952768000000000L, DateTimeKind.Utc),
                TotalRating = null,
                TotalRatingCount = null,
                IgdbUrl = "https://www.igdb.com/games/bs-zelda-no-densetsu-inishie-no-sekiban-dai-1-wa",
                GameTypeId = 6L,
