            [178062L] = new()
            {
                Id = 178062L,
                Name = "BS Zelda no Densetsu: Inishie no Sekiban - Dai-2-wa",
                Slug = "bs-zelda-no-densetsu-inishie-no-sekiban-dai-2-wa",
                Summary = "The second part (week) of BS Zelda no Densetsu: Inishie no Sekiban.",
                Storyline =
                    "The Monsters Return - Week 2\nSome time after Zelda sets off to return to Hyrule Castle, a Soldier who guards the Eastern Palace appears before Aginah, claiming that a horde of monsters had appeared, killing the other guards protecting the temple. As the sole survivor, he passes this information on to Aginah despite his injuries. Aginah remains with the youth, hoping Zelda\u0027s belief in him or her is true. When the child awakens, Aginah informs the youngster of the monsters that are attacking their land, and explains that it is dangerous to go alone without a weapon. He states that a Sword and Shield can be found in the Eastern Palace, but he himself is too old to go there. He lends the youth an Ocarina and a Bug-Catching Net belonging to Saharshala, and also a Bottle containing a magical Golden Bee. He informs the child that the bee will attack monsters, but flee from anyone who holds a blade, and that the ocarina can be used to return to the entrance of a dungeon. With that, the new hero embarks on his or her journey.",
                FirstReleaseDate = new DateTime(629958816000000000L, DateTimeKind.Utc),
                TotalRating = null,
                TotalRatingCount = null,
                IgdbUrl = "https://www.igdb.com/games/bs-zelda-no-densetsu-inishie-no-sekiban-dai-2-wa",
                GameTypeId = 6L,
